using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System.Diagnostics;

namespace MyNamespace
{
    public static class MyFunction
    {
        [FunctionName("MyFunction")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = null)] HttpRequest req,
            ILogger log)
        {
            log.LogInformation("C# HTTP trigger function processed a request.");

            // Log HTTP request headers and body content
            foreach (var header in req.Headers)
            {
                log.LogInformation($"Header: {header.Key} = {header.Value}");
            }
            string bodyContent = await new StreamReader(req.Body).ReadToEndAsync();
            log.LogInformation($"Body content: {bodyContent}");

            // Log database queries with parameters
            using (var dbContext = new MyDbContext())
            {
                var queryResult = dbContext.Users.Where(u => u.Name == "John Doe").ToList();
                log.LogInformation($"Query result: {queryResult}");
            }

            // Log full exception details for any errors
            try
            {
                // some code that throws an error
            }
            catch (Exception ex)
            {
                var exception = new Exception(ex.Message, ex);
                log.LogError(exception, "An error occurred while processing the request.");
            }

            return new OkResult();
        }
